class Solution:
    def permute(self, nums: List[int]) -> List[List[int]]:

        result: List[List[int]] = []

        def dfs(temp: List[int], left: List[int]):
            if not left:
                result.append(temp)
            for index, item in enumerate(left):
                one = temp.copy()
                one.append(item)
                two = left.copy()
                two.pop(index)
                dfs(one, two)

        dfs([], nums)

        return result
